import Foundation
import UIKit

enum AnalyticsEvent: String {
    case userLogin = "USER_LOGIN"
    case userLogout = "USER_LOGOUT"
    case apiCall = "API_CALL"
    case userDataChange = "USER_DATA_CHANGE"
    case errorOccurred = "ERROR_OCCURRED"
    case appLaunch = "APP_LAUNCH"
    case screenView = "SCREEN_VIEW"
}

struct AnalyticsData {
    let eventId: String
    let userId: String?
    let userEmail: String?
    let timestamp: Date
    let payload: [String: Any]?
    let error: Error?
    
    init(eventId: String, userId: String? = nil, userEmail: String? = nil, payload: [String: Any]? = nil, error: Error? = nil) {
        self.eventId = eventId
        self.userId = userId
        self.userEmail = userEmail
        self.timestamp = Date()
        self.payload = payload
        self.error = error
    }
}

class AnalyticsLogger {
    static let shared = AnalyticsLogger()
    
    private init() {}
    
    func logUserLogin(userId: String, email: String) {
        let data = AnalyticsData(
            eventId: AnalyticsEvent.userLogin.rawValue,
            userId: userId,
            userEmail: email
        )
        
        logEvent(data)
    }
    
    func logUserLogout() {
        let data = AnalyticsData(eventId: AnalyticsEvent.userLogout.rawValue)
        logEvent(data)
    }
    
    func logAPICall(url: String, method: String, request: [String: Any]?, response: [String: Any]?, error: Error? = nil) {
        var payload: [String: Any] = [
            "url": url,
            "method": method
        ]
        
        if let request = request {
            payload["request"] = request
        }
        
        if let response = response {
            payload["response"] = response
        }
        
        let data = AnalyticsData(
            eventId: AnalyticsEvent.apiCall.rawValue,
            payload: payload,
            error: error
        )
        
        logEvent(data)
    }
    
    func logUserDataChange(userId: String, changes: [String: Any]) {
        let data = AnalyticsData(
            eventId: AnalyticsEvent.userDataChange.rawValue,
            userId: userId,
            payload: ["changes": changes]
        )
        
        logEvent(data)
    }
    
    func logError(error: Error, context: String = "") {
        let data = AnalyticsData(
            eventId: AnalyticsEvent.errorOccurred.rawValue,
            error: error,
            payload: ["context": context]
        )
        
        logEvent(data)
    }
    
    func logAppLaunch() {
        let data = AnalyticsData(eventId: AnalyticsEvent.appLaunch.rawValue)
        logEvent(data)
    }
    
    func logScreenView(screenName: String) {
        let data = AnalyticsData(
            eventId: AnalyticsEvent.screenView.rawValue,
            payload: ["screen": screenName]
        )
        
        logEvent(data)
    }
    
    private func logEvent(_ data: AnalyticsData) {
        let timestamp = data.timestamp.formatted(dateStyle: .medium, timeStyle: .medium)
        var logMessage = "[Analytics] \(timestamp) - Event: \(data.eventId)"
        
        if let userId = data.userId {
            logMessage += " | User ID: \(userId)"
        }
        
        if let userEmail = data.userEmail {
            logMessage += " | Email: \(userEmail)"
        }
        
        if let payload = data.payload {
            logMessage += " | Payload: \(payload)"
        }
        
        if let error = data.error {
            logMessage += " | Error: \(error.localizedDescription)"
        }
        
        NSLog(logMessage)
        print(logMessage)
    }
}

// Extension for API service logging
extension AnalyticsLogger {
    func logAuthenticationFlow(started: Bool, userId: String? = nil, email: String? = nil) {
        let eventId = started ? "AUTH_FLOW_STARTED" : "AUTH_FLOW_COMPLETED"
        let data = AnalyticsData(
            eventId: eventId,
            userId: userId,
            userEmail: email
        )
        logEvent(data)
    }
    
    func logTokenRefresh(token: String) {
        let data = AnalyticsData(
            eventId: "TOKEN_REFRESHED",
            payload: ["token": token]
        )
        logEvent(data)
    }
    
    func logNetworkRequest(url: String, method: String, headers: [String: String]?, body: Data?) {
        var payload: [String: Any] = [
            "url": url,
            "method": method
        ]
        
        if let headers = headers {
            payload["headers"] = headers
        }
        
        if let body = body {
            payload["body"] = String(data: body, encoding: .utf8) ?? "Body data"
        }
        
        let data = AnalyticsData(
            eventId: "NETWORK_REQUEST",
            payload: payload
        )
        
        logEvent(data)
    }
    
    func logNetworkResponse(statusCode: Int, response: Data?, headers: [String: String]?) {
        var payload: [String: Any] = [
            "statusCode": statusCode
        ]
        
        if let headers = headers {
            payload["headers"] = headers
        }
        
        if let response = response {
            payload["response"] = String(data: response, encoding: .utf8) ?? "Response data"
        }
        
        let data = AnalyticsData(
            eventId: "NETWORK_RESPONSE",
            payload: payload
        )
        
        logEvent(data)
    }
}

